import dspy
from dspy.utils import DummyLM


class TravelSpecialist(dspy.Module):
    def __init__(self):
        super().__init__()
        # Built ONCE. No max_iters fixed here; the budget is chosen per call.
        self.agent = dspy.ReAct('request -> reply', tools=[self.search_trips, self.book_trip])

    def search_trips(self, origin: str, destination: str) -> list[dict]:
        return [
            {'id': 'T1', 'origin': origin, 'destination': destination, 'price': 120},
            {'id': 'T2', 'origin': origin, 'destination': destination, 'price': 180},
        ]

    def book_trip(self, trip: dict, traveler: str) -> str:
        return 'Booked {} for {} at ${}.'.format(trip['id'], traveler, trip['price'])

    def handle_travel(self, request: str) -> str:
        # Inner layer gets its own larger budget, passed in the CALL (not the constructor).
        return self.agent(request=request, max_iters=2).reply


class BillingSpecialist(dspy.Module):
    def __init__(self):
        super().__init__()
        self.agent = dspy.ReAct('request -> reply', tools=[self.lookup_invoice, self.issue_credit])

    def lookup_invoice(self, invoice_id: str) -> str:
        return f'invoice {invoice_id}: unpaid'

    def issue_credit(self, invoice_id: str, amount: int) -> str:
        return f'credit of ${amount} issued for {invoice_id}'

    def handle_billing(self, request: str) -> str:
        return self.agent(request=request, max_iters=2).reply


class Dispatcher(dspy.Module):
    def __init__(self):
        super().__init__()
        self.travel = TravelSpecialist()
        self.billing = BillingSpecialist()
        # Router built ONCE and reused for every request.
        self.router = dspy.ReAct(
            'request -> response',
            tools=[self.travel.handle_travel, self.billing.handle_billing],
        )

    def forward(self, request: str, route_budget: int = 1) -> dspy.Prediction:
        # Outer routing layer is capped to one step PER CALL via the call-time
        # max_iters override, so it delegates to a single specialist and stops.
        return self.router(request=request, max_iters=route_budget)


