import dspy
from dspy.utils import DummyLM


class TinyWorld:
    def __init__(self):
        self.room = 'hall'
        self.inventory: list[str] = []

    def ask(self, question: str) -> str:
        return 'The brass key is in the attic.' if 'key' in question.lower() else 'I only know about the key.'

    def move(self, direction: str) -> str:
        self.room = 'attic' if direction.lower() == 'attic' else self.room
        return f'You are now in the {self.room}.'

    def take(self, item: str) -> str:
        if self.room == 'attic' and item.lower() == 'brass key':
            self.inventory.append('brass key')
            return 'You picked up the brass key.'
        return f'There is no {item} here.'


class QuestAgent(dspy.Module):
    def __init__(self, env: TinyWorld):
        super().__init__()
        self.agent = dspy.ReAct('goal -> outcome', tools=[env.ask, env.move, env.take], max_iters=3)

    def forward(self, goal: str) -> dspy.Prediction:
        return self.agent(goal=goal)


